import { cn } from "@/lib/utils";

function SpinnerCircle5({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <>
      <style>{`
        @keyframes loading-ui-spinner-circle-5-spin {
          to {
            transform: rotate(360deg);
          }
        }
      `}</style>
      <div
        className={cn(
          "size-7 rounded-full border-[3px] border-white border-t-primary border-b-primary",
          className,
        )}
        style={{
          animationName: "loading-ui-spinner-circle-5-spin",
          animationDuration: "var(--duration, 1s)",
          animationTimingFunction: "linear",
          animationIterationCount: "infinite",
          ...style,
        }}
        {...props}
      />
    </>
  );
}

export { SpinnerCircle5 };
